import { useParams } from "react-router-dom";
import { useSmartBack } from "@/hooks/useSmartBack";
import { useTranslation } from "react-i18next";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useQueryClient } from "@tanstack/react-query";
import { ArrowLeft, Loader2 } from "lucide-react";
import { Button } from "@/components/ui/button";
import PostCard from "@/components/community/PostCard";
import RecipeDetailContent from "@/components/community/recipe/RecipeDetailContent";
import RestaurantComments from "@/components/RestaurantComments";
import TranslateButton from "@/components/TranslateButton";
import { useCommunityPost } from "@/hooks/useCommunityPosts";
import { PullToRefresh } from "@/components/PullToRefresh";
import { supabase } from "@/integrations/supabase/client";
import { usePageView } from "@/hooks/usePageView";

interface ExtendedPost {
  post_type?: string;
  [key: string]: any;
}

const CORE_TRANSLATION_LANGS = new Set(["zh", "en", "pt"]);

const normalizeLang = (lang: string) => lang.split("-")[0];

const buildRecipeTranslationText = (post: ExtendedPost) => {
  const parts: string[] = [];

  if (post.recipe_name) {
    parts.push(`[NAME]${post.recipe_name}`);
  }

  if (post.content && post.content.trim() && !post.content.includes("主要配料：")) {
    parts.push(`[CONTENT]${post.content}`);
  }

  if (post.ingredients && Array.isArray(post.ingredients) && post.ingredients.length > 0) {
    const ingredientNames = post.ingredients.map((i: any) => i?.name).filter(Boolean).join("|");
    if (ingredientNames) parts.push(`[INGREDIENTS]${ingredientNames}`);
  }

  if (post.steps && Array.isArray(post.steps) && post.steps.length > 0) {
    const stepDescs = [...post.steps]
      .sort((a: any, b: any) => (a?.order ?? 0) - (b?.order ?? 0))
      .map((s: any) => s?.description)
      .filter(Boolean)
      .join("|");
    if (stepDescs) parts.push(`[STEPS]${stepDescs}`);
  }

  return parts.join("\n---\n");
};

const PostDetail = () => {
  const { id } = useParams<{ id: string }>();
  const { t, i18n } = useTranslation();
  const goBack = useSmartBack("/community");
  const queryClient = useQueryClient();
  const { data: post, isLoading, error } = useCommunityPost(id || "");
  const viewTracked = useRef(false);
  const autoTranslateKeyRef = useRef("");
  const [translatedContent, setTranslatedContent] = useState<string | null>(null);

  // Track page view for analytics
  usePageView({ pageType: "post", targetId: id });

  const currentLang = useMemo(() => normalizeLang(i18n.language), [i18n.language]);

  const translationText = useMemo(() => {
    if (!post) return "";
    const extPost = post as ExtendedPost;
    if (extPost.post_type === "recipe") {
      return buildRecipeTranslationText(extPost);
    }
    return post.content || "";
  }, [post]);

  // Increment view count once when post is loaded
  useEffect(() => {
    if (id && post && !viewTracked.current) {
      viewTracked.current = true;
      supabase.rpc("increment_post_views", { post_id: id }).then(({ error: rpcError }) => {
        if (rpcError) console.error("Failed to increment views:", rpcError);
      });
    }
  }, [id, post]);

  // Reset translation when language/post changes
  useEffect(() => {
    autoTranslateKeyRef.current = "";
    setTranslatedContent(null);
  }, [id, currentLang]);

  // Auto-translate AI recipe posts for non-core languages
  useEffect(() => {
    if (!post || !translationText.trim()) return;

    const extPost = post as ExtendedPost;
    const isRecipe = extPost.post_type === "recipe";
    const isAiRecipe = Boolean(extPost.ai_recipe_source);

    if (!isRecipe || !isAiRecipe || CORE_TRANSLATION_LANGS.has(currentLang)) return;

    const cacheKey = `${post.id}:${currentLang}:${translationText.length}`;
    if (autoTranslateKeyRef.current === cacheKey) return;
    autoTranslateKeyRef.current = cacheKey;

    (async () => {
      try {
        const { data, error: invokeError } = await supabase.functions.invoke("translate-content", {
          body: { text: translationText, targetLang: currentLang },
        });

        if (invokeError) {
          console.error("[PostDetail] Auto translation failed:", invokeError);
          return;
        }

        if (data?.translatedText) {
          setTranslatedContent(data.translatedText);
        }
      } catch (err) {
        console.error("[PostDetail] Auto translation failed:", err);
      }
    })();
  }, [post, translationText, currentLang]);

  // Pull-to-refresh handler - clears cache and forces fresh data
  const handleRefresh = useCallback(async () => {
    queryClient.removeQueries({ queryKey: ["community-post", id] });
    queryClient.removeQueries({ queryKey: ["comments", id] });

    await Promise.all([
      queryClient.invalidateQueries({ queryKey: ["community-post", id] }),
      queryClient.invalidateQueries({ queryKey: ["comments", id] }),
    ]);
  }, [queryClient, id]);

  if (isLoading) {
    return (
      <div className="container max-w-2xl mx-auto py-6 px-4 flex justify-center">
        <Loader2 className="h-8 w-8 animate-spin" />
      </div>
    );
  }

  if (error || !post) {
    return (
      <div className="container max-w-2xl mx-auto py-6 px-4">
        <div className="text-center py-12">
          <p className="text-muted-foreground">{t("community.postNotFound", "帖子不存在或已被删除")}</p>
          <Button variant="outline" className="mt-4" onClick={goBack}>
            <ArrowLeft className="h-4 w-4 mr-2" />
            {t("community.backToList", "返回社区")}
          </Button>
        </div>
      </div>
    );
  }

  const isRecipePost = (post as ExtendedPost).post_type === "recipe";

  return (
    <PullToRefresh onRefresh={handleRefresh}>
      <div className="container max-w-2xl mx-auto py-6 px-4">
        <div className="flex items-center justify-between mb-4">
          <Button variant="ghost" size="sm" onClick={goBack}>
            <ArrowLeft className="h-4 w-4 mr-2" />
            {t("community.backToList", "返回社区")}
          </Button>
          {translationText.trim() ? (
            <TranslateButton
              text={translationText}
              onTranslation={setTranslatedContent}
              className="!shadow-none !border-0 !px-2 text-muted-foreground hover:text-foreground"
            />
          ) : null}
        </div>

        {isRecipePost ? (
          <RecipeDetailContent post={post as any} externalTranslation={translatedContent} />
        ) : (
          <PostCard post={post} showActions isDetailPage externalTranslatedContent={translatedContent} />
        )}

        <div className="mt-6">
          <RestaurantComments targetId={post.id} targetType="post" />
        </div>
      </div>
    </PullToRefresh>
  );
};

export default PostDetail;
